[12754]={"大炸弹","12.5秒 施法时间\n工具:\n铁匠锤 , 弧光扳手\n施法材料:\n秘银外壳 , 地精火箭燃油 , 实心炸弹 (6), 不牢固的扳机\n(2)\n需要工程学\n(225)\n[q2]使用: 对半径10码范围内的所有敌人造成340至460点火焰伤害，并使它们瘫痪5秒。任何伤害都会打断这个效果。对60级以上目标使用的效果很差。 (1分钟 冷却)"},
[12755]={"地精炸弹箱","12.5秒 施法时间\n工具:\n铁匠锤 , 弧光扳手\n施法材料:\n秘银外壳 (2), 实心炸药 (4), 真银锭 (6), 不牢固的扳机 , 精确瞄准镜 (2)\n拾取后绑定\n饰品\n需要工程学\n(230)\n[q2]使用: 制造一个移动炸弹，它会冲向最近的敌人并爆炸，对其造成315至385点火焰伤害。 (30分钟 冷却)"},
[12758]={"[q2]地精火箭头盔","12.5秒 施法时间\n工具:\n铁匠锤 , 弧光扳手\n施法材料:\n地精施工头盔 , 地精火箭燃油 (4), 秘银锭 (4), 不牢固的扳机\n[q2]地精火箭头盔\n装备后绑定\n头部 布甲\n50护甲\n+15 耐力\n耐久: 45 / 45\n需要工程学\n(235)\n[q2]使用: 向目标冲锋，将其打傻30秒。这个技能也会使你被击倒并在短时间内昏迷。任何伤害都会唤醒目标。对60级以上的目标有可能失效。 (20分钟 冷却)"},
[12759]={"侏儒死亡射线","12.5秒 施法时间\n工具:\n铁匠锤 , 弧光扳手\n施法材料:\n秘银管 (2), 不牢固的扳机 , 死灵精华 , 亡灵腐液 (4), 秘银杆\n拾取后绑定\n饰品\n[q2]使用: 这件设备可以将你的生命能量以强力冲击波的形式发射出去，攻击你的敌人。 (5分钟 冷却)\n[q]\"使用此装置可能造成死亡或重伤。\""},
