[14514]={"闪现术","75法力值\n瞬发\n[q]将施法者传送到正前方20码的位置，路线上有阻挡物则会停止，传送可以解除施法者身上一切形式的束缚。"},
[14515]={"统御意志","30法力值 20 码范围\n2秒 施法时间"},
[14516]={"打击","近战范围\n下一个近战\n需要 近战武器\n[q]对敌人造成额外的近战伤害。"},
[14517]={"十字军打击","40法力值 近战范围\n瞬发\n需要 近战武器\n[q]对目标造成27点伤害，每次十字军打击都可使目标在受到神圣伤害时多承受10点额外神圣伤害，共可累加5次。持续30秒。"},
[14518]={"十字军打击","40法力值 近战范围\n瞬发\n需要 近战武器\n[q]对目标造成50点伤害，每次十字军打击都可使目标在受到神圣伤害时多承受20点额外神圣伤害，共可累加5次。持续30秒。"},
[14520]={"精神敏锐","[q]使你的瞬发法术所消耗的法力值减少2%。"},
[14521]={"冥想","[q]使你在施法时仍保持10%的法力值恢复速度。"},
[14522]={"坚定意志","[q]使你抵抗昏迷、恐惧和沉默效果的几率提高3%。"},
[14523]={"无声消退","[q]使你的神圣和戒律系法术造成的威胁值降低4%，并使你的法术被驱散的几率降低4%。"},
[14524]={"魔杖专精","[q]使你的魔杖伤害提高5%。"},
