[14530]={"速度","瞬发\n[q]使你的奔跑速度提高40%，持续10秒。"},
[14531]={"殉难","[q]使你有50%的几率在受到敌人的近战或远程爆击后获得专注施法效果，持续6秒。专注施法效果可以令你避免因为受到伤害而延长牧师法术的施法时间，并使你抵抗打断效果的几率提高10%。\n（特效触发几率：50%）"},
[14532]={"慢性毒药","2秒 施法时间\n[q]使附近敌人受到物理攻击时所承受的伤害提高30%，持续5分钟。"},
[14533]={"分离","瞬发\n[q]使附近的敌人在受到火焰、冰霜或奥术攻击时承受的伤害提高50%，持续5分钟。"},
