[14535]={"病弱","瞬发\n[q]使附近敌人的所有属性降低25%，持续5分钟。"},
[14537]={"六魔包","30 码范围\n瞬发\n[q]以风与火、雷与电，乃至万物的力量攻击敌人！"},
[14538]={"听觉震荡","瞬发\n[q]使附近敌人的施法速度降低35%，持续5分钟。"},
[14539]={"腐烂蛋白","瞬发\n[q]使附近敌人在受到自然系攻击时承受的伤害提高50%，在受到暗影系攻击时承受的伤害提高50%。持续5分钟。"},
