[27124]={"冰甲术","630法力值\n瞬发\n[q]使护甲值提高645点，冰霜抗性提高18点。如果敌人使用近战武器攻击施法者，他们的移动速度就有可能被降低30%，攻击间隔延长25%，冰冻效果持续5秒。法师在同一时间内只能保有一种魔法护甲效果。持续30分钟。"},
[27125]={"法师护甲","575法力值\n瞬发\n[q]对所有魔法的抗性提高18点，在施法时也可保持30%的法力值回复速度。法师在同一时间内只能保有一种魔法护甲效果。持续30分钟。"},
[27126]={"奥术智慧","700法力值 30 码范围\n瞬发\n[q]使目标的智力提高40点，持续30分钟。"},
[27127]={"奥术光辉","1800法力值 40 码范围\n瞬发\n施法材料:\n魔粉\n[q]魔法的光辉笼罩着目标所在的队伍，使他们的智力提高40点，持续1小时。"},
[27128]={"防护火焰结界","360法力值\n瞬发 30秒 冷却\n[q]吸收1125点火焰伤害，持续30秒。"},
[27130]={"魔法增效","500法力值 30 码范围\n瞬发\n[q]增强施放于目标小队成员身上的魔法效果，使其受到的法术伤害最多提高90点，治疗法术所恢复的生命值最多提高180点，持续10分钟。"},
[27131]={"法力护盾","155法力值\n瞬发\n[q]吸收715点物理伤害，同时消耗法力值。每吸收1点物理伤害，就消耗2点法力值。持续1分钟。"},
[27132]={"炎爆术","460法力值 35 码范围\n6秒 施法时间\n[q]发射一枚巨大的火球，对目标造成 866至 1094点火焰伤害，并在12秒内造成总计312点额外伤害。"},
[27133]={"冲击波","555法力值\n瞬发 30秒 冷却\n[q]施法者放出一道火焰冲击波，所有被冲击波触及的敌人都会受到 543至 638点火焰伤害并眩晕6秒。"},
[27134]={"寒冰护体","495法力值\n瞬发 30秒 冷却\n[q]立即为目标加上魔法护盾，可吸收 952点伤害，持续1分钟。只要护盾存在，受保护者的施法就不会被打断。"},
[27135]={"圣光术","710法力值 40 码范围\n2.5秒 施法时间\n[q]治疗友方目标，恢复 1773至 1971点生命值。"},
[27136]={"圣光术","840法力值 40 码范围\n2.5秒 施法时间\n[q]治疗友方目标，恢复 2196至 2446点生命值。"},
[27137]={"圣光闪现","180法力值 40 码范围\n1.5秒 施法时间\n[q]治疗友方目标，恢复 458至 513点生命值。"},
[27138]={"驱邪术","340法力值 30 码范围\n瞬发 15秒 冷却\n[q]对单一亡灵或恶魔目标造成 626至 698点神圣伤害。"},
[27139]={"神圣愤怒","825法力值2秒 施法时间 1分钟 冷却\n[q]向四面八方射出充满神圣能量的箭矢，对圣骑士周围半径20码范围内的所有亡灵和恶魔造成 637至 748点神圣伤害。"},
[27140]={"力量祝福","145法力值 30 码范围\n瞬发\n[q]为友方目标施加祝福，使其攻击强度提高220点，持续10分钟。每个圣骑士在同一时间内只能给目标施加一种祝福，同类型的祝福不能重叠。"},
[27141]={"强效力量祝福","295法力值 40 码范围\n瞬发\n施法材料:\n王者印记\n[q]使团队或小队中所有与目标职业相同的玩家都获得强效力量祝福的效果，使其攻击强度提高220点，持续30分钟。每个圣骑士在同一时间内只能给目标施加一种祝福，同类型的祝福不能重叠。"},
[27142]={"智慧祝福","150法力值 30 码范围\n瞬发\n[q]为友方目标施加祝福，每5秒恢复41点法力值，持续10分钟。每个圣骑士在同一时间内只能给目标施加一种祝福，同类型的祝福不能重叠。"},
[27143]={"强效智慧祝福","310法力值 40 码范围\n瞬发\n施法材料:\n王者印记\n[q]使团队或小队中所有与目标职业相同的玩家都获得强效智慧祝福的效果，每5秒回复41点法力值，持续30分钟。每个圣骑士在同一时间内只能给目标施加一种祝福，同类型的祝福不能重叠。"},
[27144]={"光明祝福","180法力值 30 码范围\n瞬发\n[q]为友方目标施加祝福，使圣光术为其恢复的生命值提高最多580点，圣光闪现为其恢复的生命值提高最多185点，效果持续10分钟。每个圣骑士在同一时间内只能给目标施加一种祝福，同类型的祝福不能重叠。"},
[27145]={"强效光明祝福","360法力值 40 码范围\n瞬发\n施法材料:\n王者印记\n[q]使团队或小队中所有与目标职业相同的玩家都获得强效光明祝福的效果，使圣光术为其恢复的生命值提高580点，圣光闪现为其恢复的生命值提高185点，持续30分钟。每个圣骑士在同一时间内只能给目标施加一种祝福，同类型的祝福不能重叠。"},
[27146]={"瓦塔拉克饰品的左瓣","2秒 施法时间\n施法材料:\n瓦塔拉克饰品的上半边 , 瓦塔拉克饰品的右半边\n[q]将瓦塔拉克饰品的左瓣、右瓣和上瓣组合起来。"},
[27147]={"牺牲祝福","115法力值 30 码范围\n瞬发 30秒 冷却\n[q]为小队成员施加祝福，每次该队友被击中时，圣骑士都将分担81点伤害，持续30秒。每个圣骑士在同一时间内只能给目标施加一种祝福，同类型的祝福不能重叠。"},
[27148]={"牺牲祝福","135法力值 30 码范围\n瞬发 30秒 冷却\n[q]为小队成员施加祝福，每次该队友被击中时，圣骑士都将分担104点伤害，持续30秒。每个圣骑士在同一时间内只能给目标施加一种祝福，同类型的祝福不能重叠。"},
[27149]={"虔诚光环","瞬发\n[q]使半径30码范围内的所有小队成员获得861点额外的护甲。每个圣骑士在同一时间内只能开启一种光环，且同类光环的效果无法叠加。"},
[27150]={"惩罚光环","瞬发\n[q]对30码内任何使用近战武器攻击附近小队成员的生物造成26点神圣伤害。每个圣骑士在同一时间内只能开启一种光环，且同类光环的效果无法叠加。"},
[27151]={"暗影抗性光环","瞬发\n[q]使附近半径30码范围内的所有队友的暗影抗性提高70点。每个圣骑士在同一时间内只能开启一种光环，且同类光环的效果无法叠加。"},
[27152]={"冰霜抗性光环","瞬发\n[q]使附近半径30码范围内的所有队友的冰霜抗性提高70点。每个圣骑士在同一时间内只能开启一种光环，且同类光环的效果无法叠加。"},
[27153]={"火焰抗性光环","瞬发\n[q]使附近半径30码范围内的所有队友的火焰抗性提高70点。每个圣骑士在同一时间内只能开启一种光环，且同类光环的效果无法叠加。"},
[27154]={"圣疗术","40 码范围\n瞬发 1小时 冷却\n[q]治疗一个友方目标，为其恢复相当于圣骑士的最大生命值的生命值，并为其恢复900点法力值。使用这一法术将消耗圣骑士所有的法力值。"},
[27155]={"正义圣印","260法力值\n瞬发\n[q]神圣的灵魂充满圣骑士的体内，持续30秒，令其近战攻击有一定几率造成[1.2 * ( 2324 * 1.2 * 1.03 * [Mainhand weapon max base speed] / 100) + 0.03 * ([Mainhand weapon max damage] + [Mainhand weapon min damage]) / 2 + 1]点额外的神圣伤害。双手武器每击造成的神圣伤害更高。圣骑士在同一时间内只能激活一种圣印。\n\n 释放这种圣印的能量将对目标造成 225至 246点神圣伤害。"},
[27156]={"正义圣印"},
[27157]={"正义审判"},
[27158]={"十字军圣印","210法力值\n瞬发\n[q]十字军的灵魂充满圣骑士的体内，持续30秒，使其近战攻击强度提高 495点。圣骑士的攻击速度也提高40%，但攻击时所造成的伤害会降低。圣骑士在同一时间内只能激活一种圣印。\n\n 释放这种圣印的能量将对目标造成审判效果，持续20秒。神圣系的伤害性法术对被审判的目标造成最多219点额外的神圣伤害。你的近战攻击将使得该法术的持续时间延长。每个圣骑士在同一时间内只能给目标施加一种审判效果，同类型的审判不能重叠。"},
[27159]={"十字军审判"},
[27160]={"光明圣印","280法力值\n瞬发\n[q]神圣之光充满圣骑士的体内，持续30秒，使其每次近战攻击都有一定几率回复133点生命值。圣骑士在同一时间内只能激活一种圣印。\n\n 释放这种圣印的能量将对目标造成审判效果，持续20秒。使用近战武器击中被审判的目标就有一定几率令攻击者回复95点生命值。你的近战攻击将使得该法术的持续时间延长。每个圣骑士在同一时间内只能给目标施加一种审判效果，同类型的审判不能重叠。"},
[27161]={"光明圣印"},
